static int iter = 0;

float d_dist(int p1, int p2, int num, int dim, float *coord_h)
{
	float retval = 0.0;
	for(int i = 0; i < dim; i++){
		float tmp = coord_h[(i*num)+p1] - coord_h[(i*num)+p2];
		retval += tmp * tmp;
	}
	return retval;
}

void kernel_compute_cost(int num, int dim, long x, Point *p, int K, int stride,
					float *coord_h, float *work_mem_h, int *center_table, bool *switch_membership)
{
	#pragma omp parallel for schedule(static)
	for(int tid = 0; tid < num; tid++)
	{
		float *lower = &work_mem_h[tid*stride];

		float x_cost = d_dist(tid, x, num, dim, coord_h) * p[tid].weight;

		if ( x_cost < p[tid].cost )
		{
			switch_membership[tid] = true;
			lower[K] += x_cost - p[tid].cost;
		}
		else
		{
			lower[center_table[p[tid].assign]] += p[tid].cost - x_cost;
		}
	}
}

void allocHostMem(int num, int dim)
{
	coord_h	= (float*) malloc( num * dim * sizeof(float) );
	center_table = (int*) malloc(num * sizeof(int));
	switch_membership = (bool*) malloc(num * sizeof(bool));
	p = (Point*) malloc(num * sizeof(Point));
}

void freeHostMem()
{
	free(coord_h);
	free(center_table);
	free(switch_membership);
	free(p);
}

float pgain( long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center, int *center_table, bool *switch_membership, bool isCoordChanged,
							double *serial_t, double *cpu_to_gpu_t, double *gpu_to_cpu_t, double *alloc_t, double *kernel_t, double *free_t)
{	
	int stride	= *numcenters + 1;			
	int K		= *numcenters ;				
	int num		=  points->num;				
	int dim		=  points->dim;				
	int nThread =  num;						

	work_mem_h = (float*) malloc(stride * (nThread + 1) * sizeof(float) );

	if(iter == 0)
	{
		allocHostMem(num, dim);
	}

	int count = 0;
	for( int i=0; i<num; i++)
	{
		if( is_center[i] )
		{
			center_table[i] = count++;
		}
	}

	if(isCoordChanged || iter == 0)
	{
		for(int i=0; i<dim; i++)
		{
			for(int j=0; j<num; j++)
			{
				coord_h[ (num*i)+j ] = points->p[j].coord[i];
			}
		}
	}

	// Initialize work_mem_h and switch_membership
	memset(work_mem_h, 0, stride * (nThread + 1) * sizeof(float));
	memset(switch_membership, 0, num * sizeof(bool));

	// Copy points to local array p
	for(int i=0; i<num; i++) {
		p[i] = points->p[i];
	}

	// Run kernel_compute_cost in parallel
	kernel_compute_cost(num, dim, x, p, K, stride, coord_h, work_mem_h, center_table, switch_membership);

	int number_of_centers_to_close = 0;
	float gl_cost_of_opening_x = z;
	float *gl_lower = &work_mem_h[stride * nThread];

	for(int i=0; i < num; i++)
	{
		if( is_center[i] )
		{
			float low = z;
		    for( int j = 0; j < num; j++ )
			{
				low += work_mem_h[ j*stride + center_table[i] ];
			}

		    gl_lower[center_table[i]] = low;

		    if ( low > 0 )
			{
				++number_of_centers_to_close;
				work_mem_h[i*stride+K] -= low;
		    }
		}
		gl_cost_of_opening_x += work_mem_h[i*stride+K];
	}

	if ( gl_cost_of_opening_x < 0 )
	{
		for(int i = 0; i < num; i++)
		{
			bool close_center = gl_lower[center_table[points->p[i].assign]] > 0 ;
			if ( switch_membership[i] || close_center )
			{
				points->p[i].cost = dist(points->p[i], points->p[x], dim) * points->p[i].weight;
				points->p[i].assign = x;
			}
		}

		for(int i = 0; i < num; i++)
		{
			if( is_center[i] && gl_lower[center_table[i]] > 0 )
			{
				is_center[i] = false;
			}
		}

		if( x >= 0 && x < num)
		{
			is_center[x] = true;
		}
		*numcenters = *numcenters + 1 - number_of_centers_to_close;
	}
	else
	{
		gl_cost_of_opening_x = 0;
	}

	free(work_mem_h);

	iter++;
	return -gl_cost_of_opening_x;
}

